import React from 'react';
import styled from 'styled-components';
import { device } from './@media';
import GlobalFonts from './5fonts/Fonts';
import {BrowserRouter, Routes, Route } from "react-router-dom";
import Main from './0main/main.jsx';
//import Nav from './3nav/nav.jsx';
//import Header from './2header/header.jsx';

const SApp = styled.div`
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 55px); 
background: green ;
color: black ;
font-family: 'TopSecretWoff2' ;

@media ${device.mobileM} { 
border: solid 0.2px blue;
font-family: 'TopSecretWoff2' ;
}
`

const Div = styled.div`
   grid-area:1/1/13/13;
   border: solid 2px red;
` 
const Button = styled.button`
background: ${props => props.primary ? "palevioletred" : "white"};
  color: ${props => props.primary ? "white" : "palevioletred"};

  font-size: 1em;
  margin: 1em;
  padding: 0.25em 1em;
  border: 2px solid palevioletred;
  border-radius: 3px;

` 


function App() {
  return (
<BrowserRouter>
<SApp >
<GlobalFonts/>

<Routes>
<Route path='/' element={<Main/>}>

</Route>
</Routes>

</SApp>
</BrowserRouter>
  );
};



export default App;
//npm start
